const GEMINI_CONFIG = {
  // スクリプトプロパティ 'GEMINI_API_KEY'
  API_KEY: PropertiesService.getScriptProperties().getProperty('GEMINI_API_KEY'),
  MODEL_NAME: 'gemini-2.5-flash',
};

/**
 * デバッグログをスプレッドシートに記録する
 * @param {string} msg 記録するメッセージ
 */
function logToSheet_(msg) {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    let sh = ss.getSheetByName('DEBUG_LOG');
    if (!sh) sh = ss.insertSheet('DEBUG_LOG');
    sh.appendRow([new Date(), String(msg)]);
  } catch (e) { }
}

/**
 * AIシステムが利用可能かチェックする
 * @returns {boolean} AIシステムが利用可能であればtrue
 */
function isAiSystemReady_() {
  if (!GEMINI_CONFIG.API_KEY) {
    logToSheet_('【システム通知】GEMINI_API_KEY がスクリプトプロパティに設定されていません。スプレッドシートの「設定」などを確認してください。');
    return false;
  }
  return true;
}

/**
 * Gemini（Vertex AI 互換）を通じてランキング分析を実行
 * @param {Array} contextData 現在の計算式で出された上位曲リスト
 * @param {string} typeLabel 'Daily' or 'Weekly'
 */
function analyzeRankingWithAi(contextData, typeLabel) {
  if (!isAiSystemReady_()) {
    logToSheet_('AI System is not ready or keys are missing. Skipping analysis.');
    return null;
  }

  try {
    const totalSongs = contextData.length;
    const chunkSize = 6; // 1回あたり6曲ずつ解析 (30曲を5回で処理)
    const allResultsMap = new Map();

    SpreadsheetApp.getActiveSpreadsheet().toast(`AI分析を開始します (全${totalSongs}曲 / ${chunkSize}曲ずつ分割実行)...`, 'Gemini AI', 5);
    logToSheet_(`Starting Chunked Gemini Analysis for ${typeLabel} (Total: ${totalSongs}, Chunk: ${chunkSize})`);

    for (let i = 0; i < totalSongs; i += chunkSize) {
      const chunkData = contextData.slice(i, i + chunkSize);
      const simplifiedData = chunkData.map(c => ({
        id: c.id,
        rank: c.rank,
        prevRank: c.prevRank,
        change: c.rankChange,
        artist: c.artist,
        title: c.title,
        role: c.role,
        views: c.views,
        growth: c.growth,
        heat: c.heat,
        comments_sample: fetchComments_(c.id)
      }));

      const prompt = `
Generate localized insights and normalize naming for these ${simplifiedData.length} Cambodian songs.
【Data】
${JSON.stringify(simplifiedData)}

【Strict Instructions for artist & title】
- Support both Khmer and English scripts. DO NOT remove Khmer script if it's the primary name.
- Identify the ACTUAL performing artist(s).
- For cleaning: Remove suffixes like "Official", "Official Channel", "Production", etc.
- title: Remove artist names and label names. Show ONLY the pure song title.

【Insight Tasks】
1. insight (English): Narrative based on DATA TRENDS (Momentum, Stability, Debut).
2. shortInsight (English): 8-10 words summarizing the chart performance factor.
3. aiScore: 0-100 score reflecting growth momentum.
4. commentQualityScore: Rate authenticity (0.0 to 1.0). 1.0=Natural, <0.7=Repetitive/Bot-like, <0.5=Spam.
5. genre: e.g., Khmer Pop, Hip Hop.
6. visualConcept: 1-2 words.

【Format】 JSON Array of objects with keys: id, artist, title, aiScore, commentQualityScore, insight, shortInsight, genre, visualConcept.
`;

      logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} call...`);
      const response = callGeminiApi_(prompt);
      if (!response) {
        logToSheet_(`Batch ${Math.floor(i / chunkSize) + 1} returned null. Skipping.`);
        continue;
      }

      // JSON抽出
      let jsonStr = response.trim();
      if (jsonStr.startsWith('```json')) jsonStr = jsonStr.substring(7);
      else if (jsonStr.startsWith('```')) jsonStr = jsonStr.substring(3);
      if (jsonStr.endsWith('```')) jsonStr = jsonStr.substring(0, jsonStr.length - 3);
      jsonStr = jsonStr.trim();

      try {
        const result = JSON.parse(jsonStr);
        const results = Array.isArray(result) ? result : (result.results || []);
        results.forEach(item => {
          if (item.id) allResultsMap.set(String(item.id), item);
          else allResultsMap.set(`${item.artist} - ${item.title}`, item);
        });
      } catch (parseError) {
        logToSheet_(`Batch Batch ${Math.floor(i / chunkSize) + 1} JSON Parse Error: ${parseError.message}. Snippet: ${jsonStr.slice(0, 50)}...`);
      }
    }

    logToSheet_(`Total results collected: ${allResultsMap.size}`);
    return allResultsMap.size > 0 ? allResultsMap : null;

  } catch (e) {
    logToSheet_('Gemini Chunked Analysis Error: ' + e.message + '\n' + e.stack);
    return null;
  }
}

/**
 * Gemini API 呼び出し用の内部関数 (Vertex AI API 互換)
 */
function callGeminiApi_(prompt) {
  const url = `https://generativelanguage.googleapis.com/v1/models/${GEMINI_CONFIG.MODEL_NAME}:generateContent?key=${GEMINI_CONFIG.API_KEY}`;
  const maxRetries = 5;
  let retryCount = 0;
  let backoffMs = 15000;

  const payload = {
    contents: [{
      parts: [{ text: prompt }]
    }],
    generationConfig: {
      temperature: 0.1,
      topP: 0.95,
      maxOutputTokens: 16384
    },
    safetySettings: [
      { category: "HARM_CATEGORY_HARASSMENT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_HATE_SPEECH", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_SEXUALLY_EXPLICIT", threshold: "BLOCK_NONE" },
      { category: "HARM_CATEGORY_DANGEROUS_CONTENT", threshold: "BLOCK_NONE" },
    ]
  };

  const options = {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  while (retryCount < maxRetries) {
    const response = UrlFetchApp.fetch(url, options);
    const resCode = response.getResponseCode();
    const resText = response.getContentText();

    if (resCode === 200) {
      if (!resText) {
        logToSheet_("Gemini API Error: Empty response text");
        return null;
      }
      const resJson = JSON.parse(resText);
      if (!resJson.candidates || !resJson.candidates[0].content || !resJson.candidates[0].content.parts) {
        logToSheet_("Gemini API Error: Unexpected response structure : " + resText);
        return null;
      }
      
      // トークン使用量の記録
      if (resJson.usageMetadata && resJson.usageMetadata.totalTokenCount) {
        updateApiUsage_('Gemini', resJson.usageMetadata.totalTokenCount);
      } else {
        updateApiUsage_('Gemini', 0); // Count request even if tokens missing
      }
      
      return resJson.candidates[0].content.parts[0].text;
    }

    if (resCode === 429 || resCode === 500 || resCode === 503 || resCode === 504) {
      const msg = `API混雑または一時的なエラー (Code: ${resCode}, Retry ${retryCount + 1}/${maxRetries}): ${backoffMs / 1000}秒待機します...`;
      SpreadsheetApp.getActiveSpreadsheet().toast(msg, 'Gemini AI', 10);
      logToSheet_(`Gemini API ${resCode} (Retry ${retryCount + 1}/${maxRetries}): Waiting ${backoffMs}ms... Error: ${resText.slice(0, 200)}`);
      Utilities.sleep(backoffMs);
      retryCount++;
      backoffMs *= 2;
      if (backoffMs > 60000) backoffMs = 60000; // Cap backoff at 60s
      continue;
    }

    logToSheet_(`Gemini API Error (${resCode}) at ${url.split('?')[0]}: ${resText}`);
    return null; // Non-retryable error
  }

  logToSheet_("Gemini API Error: Max retries reached for 429.");
  return null;
}

/**
 * AI設定の状態を確認し、ログに出力する。
 */
function checkAiConfiguration() {
  const key = PropertiesService.getScriptProperties().getProperty('GEMINI_API_KEY');
  if (!key) {
    Logger.log('❌ GEMINI_API_KEY が設定されていません。Project Settings > Script Properties に追加してください。');
  } else {
    Logger.log('✅ GEMINI_API_KEY は設定されています (末尾: ...' + key.slice(-4) + ')');
    testListModels(); // 通信テスト
  }
}

/**
 * 利用可能なモデル一覧をログに出力し、APIキーの有効性をテスト。
 */
function testListModels() {
  // モデル一覧取得は v1beta のみサポート
  const url = `https://generativelanguage.googleapis.com/v1/models?key=${GEMINI_CONFIG.API_KEY}`;
  try {
    const response = UrlFetchApp.fetch(url, { muteHttpExceptions: true });
    const code = response.getResponseCode();
    const content = response.getContentText();
    if (code === 200) {
      const json = JSON.parse(content);
      const names = json.models.map(m => m.name.replace('models/', ''));
      Logger.log('【診断】利用可能なモデル一覧: ' + names.join(', '));
      Logger.log('【アドバイス】もし gemini-1.5-flash が無い場合は、上記リストにあるモデル名を PickSongs.gs の GEMINI_CONFIG.MODEL_NAME に設定してください。');
    } else {
      Logger.log(`❌ モデル一覧の取得に失敗 (Code: ${code}): ${content}`);
    }
  } catch (e) {
    Logger.log(`❌ 通信エラー: ${e.message}`);
  }
}

