function debugTop5HeatScore() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const shSnap = ss.getSheetByName(CFG.SHEET_SNAPSHOT);
  const snap = shSnap.getDataRange().getValues();
  if (snap.length < 2) return;

  const tz = Session.getScriptTimeZone();
  const toDateKey = (v) => toDateKey_(v, tz);

  const dateSet = new Set();
  for (let i = 1; i < snap.length; i++) {
    const dk = toDateKey(snap[i][0]);
    if (dk) dateSet.add(dk);
  }
  const dates = Array.from(dateSet).sort();
  if (dates.length < 2) return;
  const latestDate = dates[dates.length - 1];

  let baseDate = dates[dates.length - 2]; // For daily

  const LMap = new Map();
  const BMap = new Map();

  for (let i = 1; i < snap.length; i++) {
    const dt = toDateKey(snap[i][0]);
    const id = String(snap[i][1]).trim();
    const v = Number(snap[i][2]) || 0;
    const l = Number(snap[i][3]) || 0;
    const c = Number(snap[i][4]) || 0;

    if (dt === latestDate) LMap.set(id, { v, l, c });
    if (dt === baseDate) BMap.set(id, { v, l, c });
  }

  let shRank = ss.getSheetByName('TEST_RANKING');
  if (!shRank) {
    shRank = ss.getSheetByName('DailyRanking');
  }
  if (!shRank) {
    logToSheet_("ERROR: Neither TEST_RANKING nor DailyRanking sheet found.");
    return;
  }
  const rankData = shRank.getDataRange().getValues();
  const topIds = [];
  for (let i = 1; i <= 5; i++) {
    if (rankData[i] && rankData[i][22]) {
      topIds.push(rankData[i][22].trim()); // videoId is in col 23 (index 22)
    }
  }

  logToSheet_("=== HEAT SCORE MATH DEGUG ===");
  topIds.forEach((id, idx) => {
    const L = LMap.get(id);
    let B = BMap.get(id);

    // If no baseline from snap, assume 0 for exact fresh track scenario
    if (!B) B = { v: 0, l: 0, c: 0 };

    const dvRaw = L.v - B.v;
    const dlRaw = L.l - B.l;
    const dcRaw = L.c - B.c;

    const dv = Math.max(0, dvRaw);
    const dl = Math.max(0, dlRaw);
    const dc = Math.max(0, dcRaw);

    const scale = 1 + (Math.log10(L.v + 1) / 10);

    const heat_dv = 5 * Math.log(dv + 1) * scale;
    const heat_dl = 3 * Math.log(dl + 1);
    const heat_dc = 5 * Math.log(dc + 1);

    const heat = heat_dv + heat_dl + heat_dc;

    logToSheet_(`Rank ${idx + 1}: [${id}]`);
    logToSheet_(`- L.v/l/c = ${L.v}/${L.l}/${L.c} | B.v/l/c = ${B.v}/${B.l}/${B.c}`);
    logToSheet_(`- dv/dl/dc = ${dv}/${dl}/${dc}`);
    logToSheet_(`- scale(log(L.v+1)) = ${scale.toFixed(4)}`);
    logToSheet_(`- heat_dv = ${heat_dv.toFixed(4)} | heat_dl = ${heat_dl.toFixed(4)} | heat_dc = ${heat_dc.toFixed(4)}`);
    logToSheet_(`- Total Heat = ${heat.toFixed(4)}`);
  });
}

/**
 * 動画のコメントを最大100件取得してテキストとして返す
 * @param {string} videoId 
 * @returns {string} 各コメントを改行で繋いだテキスト
 */
function fetchComments_(videoId) {
  let comments = [];
  let nextPageToken = null;

  try {
    // 1ページ最大50件 × 1回 = 50件取得 (実行時間短縮のため100件から50件に制限)
    for (let i = 0; i < 1; i++) {
      const options = {
        videoId: videoId,
        maxResults: 50,
        order: 'relevance'
      };
      if (nextPageToken) options.pageToken = nextPageToken;

      const res = YouTube.CommentThreads.list('snippet', options);
      updateApiUsage_('YouTube', 1); // 1 unit
      if (!res || !res.items || res.items.length === 0) break;

      res.items.forEach(it => {
        comments.push(it.snippet.topLevelComment.snippet.textDisplay);
      });

      nextPageToken = res.nextPageToken;
      if (!nextPageToken) break;
    }

    if (comments.length === 0) return "";

    // AIへの送信データを5000文字程度に拡大し、より多くのサンプルで判定を安定させる
    return comments
      .join("\n")
      .slice(0, 5000);
  } catch (e) {
    Logger.log(`Comment Fetch Error [${videoId}]: ${e.message}`);
    return "";
  }
}

