/**
 * デイリーランキングの空いているAIインサイト部分のみを補完（修復）する
 */
function repairDailyAiInsights() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const shRank = ss.getSheetByName(CFG.SHEET_RANKING_DAILY);
  if (!shRank) return;

  const data = shRank.getDataRange().getValues();
  if (data.length < 2) return;

  const logs = [];
  const toRepair = [];
  
  // A:日付, B:順位, C:Prev, D:Artist, E:Title, F:Pub, G:Spark, H:AIScore(8), I:Insight(9), J:Short(10), K:Genre(11), L:Visual(12)... W:videoId(23)
  for (let i = 1; i < data.length; i++) {
    const aiInsight = String(data[i][8]).trim(); // AIScore が '-' か空なら対象
    if (aiInsight === '-' || aiInsight === '') {
      toRepair.push({
        row: i + 1,
        id: data[i][23],
        artist: data[i][3],
        title: data[i][4],
        rank: data[i][1],
        prevRank: data[i][2] === '-' ? 100 : parseInt(data[i][2]),
        views: data[i][17] // dv
      });
    }
  }

  if (toRepair.length === 0) {
    SpreadsheetApp.getUi().alert('修復が必要な箇所（AI空欄）は見つかりませんでした。');
    return;
  }

  logToSheet_(`AI修復を開始します: ${toRepair.length}件`);
  SpreadsheetApp.getActiveSpreadsheet().toast(`${toRepair.length}件のAI分析を修復中...`, 'AI Repair');

  // AI分析用にコンテキストを整形
  const candidatesForAi = toRepair.map(r => ({
    id: r.id,
    rank: r.rank,
    prevRank: r.prevRank,
    artist: r.artist,
    title: r.title,
    views: r.views,
    heat: 100, // Dummy
    growth: 0.1 // Dummy
  }));

  const aiResults = analyzeRankingWithAi(candidatesForAi, 'Daily (Repair)');
  if (!aiResults) {
    SpreadsheetApp.getUi().alert('AI分析（修復）に失敗しました。時間をおいて再度お試しください。');
    return;
  }

  let successCount = 0;
  toRepair.forEach(item => {
    const aiData = aiResults.get(String(item.id)) || aiResults.get(`${item.artist} - ${item.title}`);
    if (aiData) {
      // H:AIScore(8), I:Insight(9), J:Short(10), K:Genre(11), L:Visual(12)
      const values = [
        [
          aiData.aiScore || aiData.aiscore || 50,
          aiData.insight || aiData.aiInsight || '-',
          aiData.shortInsight || aiData.shortinsight || '-',
          aiData.genre || '-',
          aiData.visualConcept || '-'
        ]
      ];
      shRank.getRange(item.row, 8, 1, 5).setValues(values);
      successCount++;
    }
  });

  logToSheet_(`AI修復完了: ${successCount}/${toRepair.length}件`);
  SpreadsheetApp.getUi().alert(`✅ AI修復が完了しました！\n\n正常に補完: ${successCount}件\n失敗: ${toRepair.length - successCount}件`);
}
